    arrParam[7] = ''; //직급
    arrParam[8] = (scwin.parentFrame.scwin.hid_txt_inqDt == '99999999') ? scwin.strCurDate : scwin.parentFrame.scwin.hid_txt_inqDt ;  //작업일
